    <script>
        // --- START OF BookmarksManager ---
        class BookmarksManager {
            constructor() {
                this.bookmarks = [];
                this.isInitialized = false;
            }

            async initialize() {
                if(window.electronAPI) {
                    this.bookmarks = await window.electronAPI.getBookmarks();
                } else {
                    const stored = localStorage.getItem('tnf-bookmarks');
                    this.bookmarks = stored ? JSON.parse(stored) : [];
                }
                this.createBookmarksUI();
                this.isInitialized = true;
            }

            async saveBookmarks() {
                if(window.electronAPI) {
                    await window.electronAPI.saveBookmarks(this.bookmarks);
                } else {
                    localStorage.setItem('tnf-bookmarks', JSON.stringify(this.bookmarks));
                }
            }

            async addBookmark(bookmark) {
                if (this.isBookmarked(bookmark.url)) return;
                this.bookmarks.unshift(bookmark);
                await this.saveBookmarks();
                window.browserHub.showToast('Bookmark added!', 'success');
            }

            async removeBookmark(url) {
                this.bookmarks = this.bookmarks.filter(b => b.url !== url);
                await this.saveBookmarks();
                 window.browserHub.showToast('Bookmark removed!', 'success');
            }

            isBookmarked(url) {
                return this.bookmarks.some(b => b.url === url);
            }

            getBookmarks() {
                return this.bookmarks;
            }

            createBookmarksUI() { /* UI creation logic would go here if needed as a modal */ }
        }

        // --- START OF SettingsManager ---
        class SettingsManager {
             constructor() {
                this.settings = {};
                this.isInitialized = false;
            }

            async initialize() {
                const defaultSettings = this.getDefaultSettings();
                 if(window.electronAPI) {
                    const storedSettings = await window.electronAPI.getSettings();
                    this.settings = { ...defaultSettings, ...storedSettings };
                } else {
                     const stored = localStorage.getItem('tnf-settings');
                    this.settings = stored ? { ...defaultSettings, ...JSON.parse(stored) } : defaultSettings;
                }
                this.isInitialized = true;
                this.applySettings();
            }

            getDefaultSettings() {
                return { theme: 'dark', homePage: 'https://thenewfuse.com' };
            }

            async saveSettings() {
                 if(window.electronAPI) {
                    await window.electronAPI.saveSettings(this.settings);
                } else {
                    localStorage.setItem('tnf-settings', JSON.stringify(this.settings));
                }
            }

            getSetting(key) { return this.settings[key]; }
            async setSetting(key, value) {
                this.settings[key] = value;
                await this.saveSettings();
                this.applySetting(key, value);
            }

            applySettings() {
                Object.entries(this.settings).forEach(([key, value]) => this.applySetting(key, value));
            }

            applySetting(key, value) {
                if (key === 'theme') {
                    document.documentElement.setAttribute('data-theme', value);
                }
            }
        }
        window.settingsManager = new SettingsManager();

        // --- START OF Enhanced Service/MCP Clients ---
