        class EnhancedServiceManager {
            async initialize() { console.log("Service Manager Initialized"); }
            async getAvailableServices() {
                return [
                    { id: 'agents', name: 'AI Agents', description: 'Manage and orchestrate AI agents.' },
                    { id: 'workflows', name: 'Workflow Engine', description: 'Create and run complex workflows.' },
                    { id: 'resources', name: 'Resource Manager', description: 'Access shared data and resources.' },
                    { id: 'tools', name: 'Tool Registry', description: 'Discover and use available tools.' },
                    { id: 'mcp', name: 'MCP Dashboard', description: 'Monitor the core MCP server.' }
                ];
            }
            async activateService(serviceId) { console.log(`Activating service ${serviceId}`); }
        }
        class EnhancedGraphicsEngine { async initialize() { console.log("Graphics Engine Initialized"); } }

        // --- START OF BrowserHub ---
        class BrowserHub {
            constructor() {
                this.tabs = new Map();
                this.activeTabId = null;
                this.tabCounter = 0;
                this.bookmarks = new BookmarksManager();
                this.settings = window.settingsManager;
                this.serviceManager = null;
                this.graphicsEngine = null;
                this.activeNativeView = 'welcome-screen';
                this.init();
            }

            async init() {
                console.log('Initializing Ultimate Browser Hub...');
                await this.initializeComponents();
                this.bindEvents();
                await this.loadInitialState();
                console.log('Ultimate Browser Hub initialized successfully');
            }

            async initializeComponents() {
                this.serviceManager = new EnhancedServiceManager();
                await this.serviceManager.initialize();
                this.graphicsEngine = new EnhancedGraphicsEngine();
                await this.graphicsEngine.initialize();
                await this.bookmarks.initialize();
                await this.settings.initialize();
            }

            bindEvents() {
                // Window controls
                document.getElementById('minimize-btn').addEventListener('click', () => this.minimizeWindow());
                document.getElementById('maximize-btn').addEventListener('click', () => this.maximizeWindow());
                document.getElementById('close-btn').addEventListener('click', () => this.closeWindow());

                // Sidebar
                document.getElementById('sidebar-toggle-btn').addEventListener('click', () => this.toggleSidebar());

                // Navigation
                document.getElementById('back-btn').addEventListener('click', () => this.goBack());
                document.getElementById('forward-btn').addEventListener('click', () => this.goForward());
                document.getElementById('reload-btn').addEventListener('click', () => this.reload());
                document.getElementById('home-btn').addEventListener('click', () => this.goHome());

                // URL bar & Welcome search
                const urlInput = document.getElementById('url-input');
                urlInput.addEventListener('keydown', (e) => { if (e.key === 'Enter') this.navigateTo(urlInput.value); });
                const welcomeSearchInput = document.getElementById('welcome-search');
                const welcomeSearchBtn = document.getElementById('welcome-search-btn');
                welcomeSearchInput.addEventListener('keydown', (e) => { if (e.key === 'Enter') this.navigateTo(welcomeSearchInput.value); });
                welcomeSearchBtn.addEventListener('click', () => this.navigateTo(welcomeSearchInput.value));

                // Tabs
                document.getElementById('new-tab-btn').addEventListener('click', () => this.createTab());
                document.getElementById('nav-new-tab').addEventListener('click', () => this.createTab());

                // Bookmarks
                document.getElementById('add-bookmark-btn').addEventListener('click', () => this.toggleBookmark());

                // Context Menu
                document.addEventListener('contextmenu', (e) => this.handleContextMenu(e));
                document.addEventListener('click', () => this.hideContextMenu());

                // Sidebar Navigation
                document.getElementById('nav-dashboard').addEventListener('click', () => this.showNativeView('welcome-screen'));
                document.getElementById('nav-ai-chat').addEventListener('click', () => this.showNativeView('ai-chat-hub'));
                document.getElementById('nav-workflow-builder').addEventListener('click', () => this.showNativeView('workflow-builder'));

                // Dashboard Buttons
                document.getElementById('dash-launch-chat').addEventListener('click', () => this.showNativeView('ai-chat-hub'));
                document.getElementById('dash-build-workflow').addEventListener('click', () => this.showNativeView('workflow-builder'));
                document.getElementById('dash-open-ide').addEventListener('click', () => this.createTab('http://localhost:3002', 'Theia IDE'));
            }

            async loadInitialState() {
                const theme = this.settings.getSetting('theme');
                this.setTheme(theme);
                await this.loadMCPServices();
            }

            async loadMCPServices() {
                const servicesList = document.getElementById('mcp-services-list');
                try {
                    const services = await this.serviceManager.getAvailableServices();
                    servicesList.innerHTML = services.map(service => `
                        <div class="mcp-service-card">
                            <h4>${service.name}</h4>
                            <p style="font-size: 0.8rem; color: var(--text-secondary);">${service.description}</p>
                            <button class="btn btn-sm" onclick="browserHub.activateService('${service.id}')">Activate</button>
                        </div>
                    `).join('');
                } catch (error) {
                    servicesList.innerHTML = '<p>Error loading services</p>';
                }
            }

            activateService(serviceId) {
                let url = 'about:blank';
                let title = serviceId;
                switch (serviceId) {
                    case 'agents': url = 'http://localhost:3001/agents'; title = 'Agents'; break;
                    case 'workflows': url = 'http://localhost:3001/workflows'; title = 'Workflows'; break;
                    case 'mcp': url = 'http://localhost:3002'; title = 'MCP Dashboard'; break;
                }
                this.createTab(url, title);
                this.showToast(`Service '${title}' activated.`);
            }

            createTab(url = this.settings.getSetting('homePage') || 'about:blank', title = 'New Tab') {
                this.tabCounter++;
                const tabId = `tab-${this.tabCounter}`;

                const tab = { id: tabId, url, title, webview: null };
                this.tabs.set(tabId, tab);

                this.createTabElement(tab);
                this.createWebview(tab);
                this.switchTab(tabId);

                return tabId;
            }

            createTabElement(tab) {
                const tabBar = document.getElementById('tab-bar');
                const tabElement = document.createElement('div');
                tabElement.className = 'tab';
                tabElement.dataset.tabId = tab.id;
                tabElement.innerHTML = `
                    <span class="tab-title">${tab.title}</span>
                    <button class="tab-close">×</button>
                `;

                tabElement.querySelector('.tab-close').addEventListener('click', (e) => { e.stopPropagation(); this.closeTab(tab.id); });
                tabElement.addEventListener('click', () => this.switchTab(tab.id));

                tabBar.insertBefore(tabElement, document.getElementById('new-tab-btn'));
            }

            createWebview(tab) {
                const contentArea = document.getElementById('content-area');
                const webview = document.createElement('webview');
                webview.id = `webview-${tab.id}`;
                webview.src = tab.url;
                webview.style.display = 'none';

                webview.addEventListener('page-title-updated', (e) => this.updateTabInfo(tab.id, { title: e.title }));
                webview.addEventListener('did-navigate', (e) => this.updateTabInfo(tab.id, { url: e.url }));
                webview.addEventListener('page-favicon-updated', (e) => this.updateTabInfo(tab.id, { favicon: e.favicons[0] }));

                contentArea.appendChild(webview);
                tab.webview = webview;
            }

            switchTab(tabId) {
                if (this.activeTabId === tabId) return;

                // Deactivate all native views and webviews
                document.querySelectorAll('.native-content, webview').forEach(el => el.style.display = 'none');

                // Deactivate old tab
                if (this.activeTabId) {
                    document.querySelector(`[data-tab-id="${this.activeTabId}"]`)?.classList.remove('active');
                }

                // Activate new tab
                const newTab = this.tabs.get(tabId);
                newTab.webview.style.display = 'block';
                this.activeTabId = tabId;

                document.querySelector(`[data-tab-id="${tabId}"]`)?.classList.add('active');
                this.updateAddressBar(newTab.url);
                this.updateBookmarkButton();

                // Deactivate sidebar nav items
                document.querySelectorAll('.sidebar .nav-item').forEach(item => item.classList.remove('active'));
            }

            closeTab(tabId) {
                if (this.tabs.size <= 0) return;

                const tab = this.tabs.get(tabId);
                if (!tab) return;

                document.querySelector(`[data-tab-id="${tabId}"]`)?.remove();
                tab.webview?.remove();
                this.tabs.delete(tabId);

                if (this.activeTabId === tabId) {
                    const remainingTabs = Array.from(this.tabs.keys());
                    if (remainingTabs.length > 0) {
                        this.switchTab(remainingTabs[0]);
                    } else {
                        this.activeTabId = null;
                        this.showNativeView('welcome-screen');
                    }
                }
            }

            showNativeView(viewId) {
                // Deactivate all native views and webviews
                document.querySelectorAll('.native-content, webview').forEach(el => el.style.display = 'none');

                // Deactivate active tab
                if (this.activeTabId) {
                    document.querySelector(`[data-tab-id="${this.activeTabId}"]`)?.classList.remove('active');
                    this.activeTabId = null;
                }

                // Activate native view
                document.getElementById(viewId).style.display = 'flex';
                this.activeNativeView = viewId;

                this.updateAddressBar('');

                // Update sidebar active state
                document.querySelectorAll('.sidebar .nav-item').forEach(item => item.classList.remove('active'));
                const navId = `nav-${viewId.replace(/-/g, '_').replace(/_screen$/, '')}`;
                document.getElementById(navId)?.classList.add('active');
            }

            navigateTo(url) {
                if (!url.trim()) return;

                // If no tabs are open, create one. Otherwise, navigate the active one.
                let targetTabId = this.activeTabId;
                if (!targetTabId) {
                    targetTabId = this.createTab('about:blank');
                }

                const tab = this.tabs.get(targetTabId);
                if (!tab?.webview) return;

                if (!/^(https?:|file:|about:)/.test(url)) {
                    url = 'https://www.google.com/search?q=' + encodeURIComponent(url);
                }

                tab.webview.loadURL(url);
            }

            updateTabInfo(tabId, { title, url, favicon }) {
                const tab = this.tabs.get(tabId);
                if (!tab) return;

                if (title) {
                    tab.title = title;
                    const tabElement = document.querySelector(`[data-tab-id="${tabId}"] .tab-title`);
                    if (tabElement) tabElement.textContent = title;
                }
                if (url) {
                    tab.url = url;
                    if (tabId === this.activeTabId) this.updateAddressBar(url);
                }
                if (favicon) {
                    tab.favicon = favicon;
                    // TODO: Update favicon in tab UI
                }

                if (tabId === this.activeTabId) this.updateBookmarkButton();
            }

            updateAddressBar(url) { document.getElementById('url-input').value = url; }
            goBack() { this.getActiveWebview()?.goBack(); }
            goForward() { this.getActiveWebview()?.goForward(); }
            reload() { this.getActiveWebview()?.reload(); }
            goHome() { this.navigateTo(this.settings.getSetting('homePage')); }

            getActiveWebview() {
                if (!this.activeTabId) return null;
                return this.tabs.get(this.activeTabId)?.webview;
            }

            async toggleBookmark() {
                const tab = this.activeTabId ? this.tabs.get(this.activeTabId) : null;
                if (!tab) return;

                if (this.bookmarks.isBookmarked(tab.url)) {
                    await this.bookmarks.removeBookmark(tab.url);
                } else {
                    await this.bookmarks.addBookmark({ title: tab.title, url: tab.url, favicon: tab.favicon });
                }
                this.updateBookmarkButton();
            }

            updateBookmarkButton() {
                const tab = this.activeTabId ? this.tabs.get(this.activeTabId) : null;
                const btn = document.getElementById('add-bookmark-btn');
                if (btn && tab && this.bookmarks.isBookmarked(tab.url)) {
                    btn.style.color = '#ffc107'; // Bookmarked color
                } else if (btn) {
                    btn.style.color = 'var(--text-secondary)';
                }
            }

            handleContextMenu(e) {
                e.preventDefault();
                const menu = document.getElementById('context-menu');
                menu.style.display = 'block';
                menu.style.left = `${e.pageX}px`;
                menu.style.top = `${e.pageY}px`;
            }
            hideContextMenu() { document.getElementById('context-menu').style.display = 'none'; }

            setTheme(theme) { this.settings.setSetting('theme', theme); }
            toggleSidebar() { document.getElementById('sidebar').classList.toggle('collapsed'); }

            minimizeWindow() { window.electronAPI?.minimizeWindow(); }
            maximizeWindow() { window.electronAPI?.maximizeWindow(); }
            closeWindow() { window.electronAPI?.closeWindow(); }

            showToast(message, type = 'success') {
                const container = document.getElementById('toast-container');
                const toast = document.createElement('div');
                toast.className = `toast ${type}`;
                toast.textContent = message;
                container.appendChild(toast);

                setTimeout(() => {
                    toast.classList.add('show');
                    setTimeout(() => {
                        toast.classList.remove('show');
                        setTimeout(() => toast.remove(), 300);
                    }, 3000);
                }, 10);
            }
        }

        // Global context menu handler
        function contextMenuAction(action) {
            browserHub.hideContextMenu();
            const webview = browserHub.getActiveWebview();
            if (!webview) return;

            switch (action) {
                case 'back': webview.goBack(); break;
                case 'forward': webview.goForward(); break;
                case 'reload': webview.reload(); break;
                case 'bookmark': browserHub.toggleBookmark(); break;
                case 'view-source': browserHub.navigateTo('view-source:' + webview.getURL()); break;
                case 'inspect': webview.openDevTools(); break;
            }
        }

        // Initialize browser when DOM is ready
        let browserHub;
        document.addEventListener('DOMContentLoaded', () => {
            window.browserHub = new BrowserHub();
        });

    </script>
</body>
</html>
```

