This custom hook provides a clean way to interact with the Electron main process.

```jsx
import { useState, useEffect } from 'react';

// A mock API for running in a standard browser
const mockElectronAPI = {
  minimizeWindow: () => console.log('Minimize Window'),
  maximizeWindow: () => console.log('Maximize Window'),
  closeWindow: () => console.log('Close Window'),
  getSettings: () => new Promise(resolve => {
    const settings = localStorage.getItem('tnf-settings');
    resolve(settings ? JSON.parse(settings) : null);
  }),
  saveSettings: (settings) => new Promise(resolve => {
    localStorage.setItem('tnf-settings', JSON.stringify(settings));
    resolve();
  }),
  getBookmarks: () => new Promise(resolve => {
    const bookmarks = localStorage.getItem('tnf-bookmarks');
    resolve(bookmarks ? JSON.parse(bookmarks) : []);
  }),
  saveBookmarks: (bookmarks) => new Promise(resolve => {
    localStorage.setItem('tnf-bookmarks', JSON.stringify(bookmarks));
    resolve();
  }),
};

export const useElectron = () => {
  const [isElectron, setIsElectron] = useState(false);

  useEffect(() => {
    if (window.electronAPI) {
      setIsElectron(true);
    }
  }, []);

  return {
    isElectron,
    api: isElectron ? window.electronAPI : mockElectronAPI,
  };
};
