import { useState, useEffect, useCallback } from 'react';
import { useElectron } from './useElectron';

export const useBookmarks = () => {
  const { api } = useElectron();
  const [bookmarks, setBookmarks] = useState([]);

  useEffect(() => {
    const loadBookmarks = async () => {
      const storedBookmarks = await api.getBookmarks();
      setBookmarks(storedBookmarks || []);
    };
    loadBookmarks();
  }, [api]);

  const saveBookmarks = useCallback(async (newBookmarks) => {
    await api.saveBookmarks(newBookmarks);
  }, [api]);

  const addBookmark = useCallback(async (bookmark) => {
    if (bookmarks.some(b => b.url === bookmark.url)) return;
    const newBookmarks = [bookmark, ...bookmarks];
    setBookmarks(newBookmarks);
    await saveBookmarks(newBookmarks);
  }, [bookmarks, saveBookmarks]);

  const removeBookmark = useCallback(async (url) => {
    const newBookmarks = bookmarks.filter(b => b.url !== url);
    setBookmarks(newBookmarks);
    await saveBookmarks(newBookmarks);
  }, [bookmarks, saveBookmarks]);

  const isBookmarked = useCallback((url) => {
    return bookmarks.some(b => b.url === url);
  }, [bookmarks]);

  return { bookmarks, addBookmark, removeBookmark, isBookmarked };
};
```

