export const useTabs = () => {
    const [tabs, setTabs] = useState([]);
    const [activeTabId, setActiveTabId] = useState(null);
    const tabCounter = useRef(0);

    const addTab = (url = 'about:blank', title = 'New Tab') => {
        tabCounter.current++;
        const newTabId = `tab-${tabCounter.current}`;
        const newTab = { id: newTabId, url, title };
        setTabs([...tabs, newTab]);
        setActiveTabId(newTabId);
        return newTabId;
    };

    const removeTab = (tabId) => {
        const tabIndex = tabs.findIndex(t => t.id === tabId);
        if (tabIndex === -1) return;

        const newTabs = tabs.filter(t => t.id !== tabId);
        setTabs(newTabs);

        if (activeTabId === tabId) {
            if (newTabs.length > 0) {
                // Activate the previous tab, or the first one if it was the first
                const newActiveIndex = Math.max(0, tabIndex - 1);
                setActiveTabId(newTabs[newActiveIndex].id);
            } else {
                setActiveTabId(null); // No tabs left
            }
        }
    };

    const updateTab = (tabId, updates) => {
        setTabs(tabs.map(tab => tab.id === tabId ? { ...tab, ...updates } : tab));
    };

    return { tabs, activeTabId, addTab, removeTab, setActiveTabId, updateTab };
};
