#### `src/App.js` (The Main Orchestrator)

```jsx
import React, { useState, useCallback, useRef, useEffect } from 'react';
import TitleBar from './components/Layout/TitleBar';
import Sidebar from './components/Layout/Sidebar';
import TabBar from './components/Browser/TabBar';
import AddressBar from './components/Browser/AddressBar';
import Dashboard from './components/Dashboard/Dashboard';
import AIChatHub from './components/AI/AIChatHub';
import WorkflowBuilder from './components/Workflow/WorkflowBuilder';

import { useSettings } from './hooks/useSettings';
import { useBookmarks } from './hooks/useBookmarks';
import { useTabs } from './hooks/useTabs';

function App() {
  const [isSidebarCollapsed, setSidebarCollapsed] = useState(false);
  const [currentView, setCurrentView] = useState('dashboard'); // 'dashboard', 'aiChat', etc., or a tabId
  const webviewRefs = useRef({});

  const { settings } = useSettings();
  const { addBookmark, removeBookmark, isBookmarked } = useBookmarks();
  const { tabs, activeTabId, addTab, removeTab, setActiveTabId, updateTab } = useTabs();

  const activeTab = tabs.find(t => t.id === activeTabId);

  // Effect to manage which view is displayed
  useEffect(() => {
    if (activeTabId) {
        setCurrentView(activeTabId);
    } else if (tabs.length === 0) {
        setCurrentView('dashboard');
    }
  }, [activeTabId, tabs.length]);

  const handleNavigate = (url) => {
    let targetTabId = activeTabId;
    if (!targetTabId) {
      targetTabId = addTab('about:blank');
    }
    const webview = webviewRefs.current[targetTabId];
    if (webview) {
        let finalUrl = url.trim();
        if (!/^(https?:|file:|about:)/.test(finalUrl)) {
            finalUrl = 'https://www.google.com/search?q=' + encodeURIComponent(finalUrl);
        }
        webview.loadURL(finalUrl);
    }
  };

  const handleSidebarNavigate = (viewId) => {
      if (viewId === 'newTab') {
          setActiveTabId(addTab(settings.homePage));
      } else {
          setActiveTabId(null); // Deactivate tabs
          setCurrentView(viewId);
      }
  };

  const handleToggleBookmark = () => {
    if (!activeTab) return;
    if (isBookmarked(activeTab.url)) {
      removeBookmark(activeTab.url);
    } else {
      addBookmark({ title: activeTab.title, url: activeTab.url });
    }
  };

  const webviewCommand = (command) => {
      const webview = activeTabId ? webviewRefs.current[activeTabId] : null;
      if (webview && webview[command]) {
          webview[command]();
      }
  };

  const handleWebviewEvent = (tabId, eventName, e) => {
      switch(eventName) {
          case 'page-title-updated':
              updateTab(tabId, { title: e.title });
              break;
          case 'did-navigate':
              updateTab(tabId, { url: e.url });
              break;
          // Add other events like 'page-favicon-updated' if needed
      }
  };

  const NativeView = () => {
      switch(currentView) {
          case 'dashboard':
              return <Dashboard onNavigate={handleSidebarNavigate} />;
          case 'aiChat':
              return <AIChatHub />;
          case 'workflowBuilder':
              return <WorkflowBuilder />;
          default:
              return null; // A tab is active
      }
  }

  return (
    <>
      <TitleBar />
      <div className="main-container">
        <Sidebar
          isCollapsed={isSidebarCollapsed}
          onToggle={() => setSidebarCollapsed(!isSidebarCollapsed)}
          activeView={!activeTabId ? currentView : null}
          onNavigate={handleSidebarNavigate}
        />
        <main className="main-content">
          <TabBar
            tabs={tabs}
            activeTabId={activeTabId}
            onSelectTab={setActiveTabId}
            onCloseTab={removeTab}
            onNewTab={() => setActiveTabId(addTab(settings.homePage))}
          />
          <AddressBar
            url={activeTab?.url || ''}
            onNavigate={handleNavigate}
            onBack={() => webviewCommand('goBack')}
            onForward={() => webviewCommand('goForward')}
            onReload={() => webviewCommand('reload')}
            onHome={() => handleNavigate(settings.homePage)}
            isBookmarked={activeTab ? isBookmarked(activeTab.url) : false}
            onToggleBookmark={handleToggleBookmark}
          />
          <div id="content-area" className="content-area">
             {/* Render all webviews but only show the active one */}
            {tabs.map(tab => (
              <webview
                key={tab.id}
                ref={el => {
                  if (el && !webviewRefs.current[tab.id]) {
                    webviewRefs.current[tab.id] = el;
                    el.addEventListener('page-title-updated', (e) => handleWebviewEvent(tab.id, 'page-title-updated', e));
                    el.addEventListener('did-navigate', (e) => handleWebviewEvent(tab.id, 'did-navigate', e));
                  }
                }}
                src={tab.url}
                style={{ display: activeTabId === tab.id ? 'flex' : 'none' }}
              />
            ))}
            {/* Render the active native view if no tab is selected */}
            {!activeTabId && <NativeView />}
          </div>
        </main>
      </div>
    </>
  );
}

export default App;

```

### Summary of the Conversion

-   **Component-Driven:** The entire application is now built from small, manageable React components, making it far easier to update and debug.
-   **Centralized Logic with Hooks:** Custom hooks (`useTabs`, `useSettings`, `useBookmarks`) contain all the business logic, keeping components clean and focused on rendering UI.
-   **Declarative UI:** The UI now automatically "reacts" to state changes (e.g., adding a tab instantly re-renders the tab bar) without manual DOM manipulation.
-   **React Flow Powered:** The workflow builder is now powered by a robust, feature-rich library designed specifically for node-based editors.
-   **Electron Ready:** The application maintains its ability to run as a desktop app by interacting with `window.electronAPI` through a dedicated hook, while also providing mock functionality to allow for development in a standard web browser.

This structure provides a professional, modern, and highly capable foundation for The New Fuse Browser Hub.

