// src/hooks/useElectron.ts
import { useState, useEffect } from 'react';
import { ElectronAPI } from '../types';

// A type-safe mock API for browser development
const mockElectronAPI: ElectronAPI = {
  minimizeWindow: () => console.log('Minimize Window'),
  maximizeWindow: () => console.log('Maximize Window'),
  closeWindow: () => console.log('Close Window'),
  getSettings: () => Promise.resolve(JSON.parse(localStorage.getItem('tnf-settings') || 'null')),
  saveSettings: (settings) => {
    localStorage.setItem('tnf-settings', JSON.stringify(settings));
    return Promise.resolve();
  },
  getBookmarks: () => Promise.resolve(JSON.parse(localStorage.getItem('tnf-bookmarks') || '[]')),
  saveBookmarks: (bookmarks) => {
    localStorage.setItem('tnf-bookmarks', JSON.stringify(bookmarks));
    return Promise.resolve();
  },
};

export const useElectron = (): { isElectron: boolean; api: ElectronAPI } => {
  const [isElectron, setIsElectron] = useState(false);

  useEffect(() => {
    setIsElectron(!!window.electronAPI);
  }, []);

  return {
    isElectron,
    api: isElectron ? window.electronAPI : mockElectronAPI,
  };
};
