// src/hooks/useTabs.ts
import { useState, useRef } from 'react';
import { Tab } from '../types';

export const useTabs = () => {
    const [tabs, setTabs] = useState<Tab[]>([]);
    const [activeTabId, setActiveTabId] = useState<string | null>(null);
    const tabCounter = useRef(0);

    const addTab = (url = 'about:blank', title = 'New Tab'): string => {
        tabCounter.current++;
        const newTabId = `tab-${tabCounter.current}`;
        const newTab: Tab = { id: newTabId, url, title };
        setTabs(prevTabs => [...prevTabs, newTab]);
        setActiveTabId(newTabId);
        return newTabId;
    };

    const removeTab = (tabId: string) => {
        const tabIndex = tabs.findIndex(t => t.id === tabId);
        if (tabIndex === -1) return;

        const newTabs = tabs.filter(t => t.id !== tabId);
        setTabs(newTabs);

        if (activeTabId === tabId) {
            if (newTabs.length > 0) {
                const newActiveIndex = Math.max(0, tabIndex - 1);
                setActiveTabId(newTabs[newActiveIndex].id);
            } else {
                setActiveTabId(null);
            }
        }
    };

    const updateTab = (tabId: string, updates: Partial<Tab>) => {
        setTabs(prevTabs => 
            prevTabs.map(tab => (tab.id === tabId ? { ...tab, ...updates } : tab))
        );
    };

    return { tabs, activeTabId, addTab, removeTab, setActiveTabId, updateTab };
};
