    setNodes((nds) => nds.concat(newNode));
  }, [setNodes]);

  return (
    <div className="native-content" style={{ padding: 0, display: 'flex', flexDirection: 'column', height: '100%' }}>
      <h2>Visual Workflow Builder</h2>
      <div className="workflow-toolbar">
         <button className="btn">New</button>
         <button className="btn">Load</button>
         <button className="btn">Save</button>
         <button className="btn btn-primary">Execute</button>
      </div>
      <div style={{ display: 'flex', flex: 1, gap: '1rem', marginTop: '1rem', overflow: 'hidden' }}>
        <NodePalette onAddNode={addNode} />
        <div className="workflow-canvas" style={{ flexGrow: 1, height: '100%' }}>
          <ReactFlow
            nodes={nodes}
            edges={edges}
            onNodesChange={onNodesChange as OnNodesChange}
            onEdgesChange={onEdgesChange as OnEdgesChange}
            onConnect={onConnect}
            fitView
          >
            <Controls />
            <Background />
          </ReactFlow>
        </div>
      </div>
    </div>
  );
};

const WorkflowBuilderProvider: React.FC = () => (
    <ReactFlowProvider>
        <WorkflowBuilder />
    </ReactFlowProvider>
);

export default WorkflowBuilderProvider;
