#### `src/context/tabsContext.tsx` (Tab State Management)

This file centralizes all logic for managing browser tabs using a reducer, which is more powerful for complex state like this.

```tsx
// src/context/tabsContext.tsx
import React, { createContext, useReducer, useRef } from 'react';
import { Tab } from '../types';
import { ADD_TAB, REMOVE_TAB, SET_ACTIVE_TAB, UPDATE_TAB } from './types';

interface TabsState {
  tabs: Tab[];
  activeTabId: string | null;
}

interface TabsContextProps extends TabsState {
  addTab: (url?: string, title?: string) => string;
  removeTab: (tabId: string) => void;
  setActiveTab: (tabId: string | null) => void;
  updateTab: (tabId: string, updates: Partial<Tab>) => void;
}

const TabsContext = createContext<TabsContextProps | undefined>(undefined);

const tabsReducer = (state: TabsState, action: any): TabsState => {
  switch (action.type) {
    case ADD_TAB:
      return {
        ...state,
        tabs: [...state.tabs, action.payload],
        activeTabId: action.payload.id,
      };
    case REMOVE_TAB:
      const newTabs = state.tabs.filter(tab => tab.id !== action.payload);
      let newActiveTabId = state.activeTabId;
      if (state.activeTabId === action.payload) {
        const tabIndex = state.tabs.findIndex(t => t.id === action.payload);
        if (newTabs.length > 0) {
          newActiveTabId = newTabs[Math.max(0, tabIndex - 1)].id;
        } else {
          newActiveTabId = null;
        }
      }
      return { ...state, tabs: newTabs, activeTabId: newActiveTabId };
    case SET_ACTIVE_TAB:
      return { ...state, activeTabId: action.payload };
    case UPDATE_TAB:
      return {
        ...state,
        tabs: state.tabs.map(tab =>
          tab.id === action.payload.tabId ? { ...tab, ...action.payload.updates } : tab
        ),
      };
    default:
      return state;
  }
};

export const TabsProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const initialState: TabsState = {
    tabs: [],
    activeTabId: null,
  };

  const [state, dispatch] = useReducer(tabsReducer, initialState);
  const tabCounter = useRef(0);

  const addTab = (url = 'about:blank', title = 'New Tab'): string => {
    tabCounter.current++;
    const newTabId = `tab-${tabCounter.current}`;
    const newTab: Tab = { id: newTabId, url, title };
    dispatch({ type: ADD_TAB, payload: newTab });
    return newTabId;
  };

  const removeTab = (tabId: string) => {
    dispatch({ type: REMOVE_TAB, payload: tabId });
  };

  const setActiveTab = (tabId: string | null) => {
    dispatch({ type: SET_ACTIVE_TAB, payload: tabId });
  };

  const updateTab = (tabId: string, updates: Partial<Tab>) => {
    dispatch({ type: UPDATE_TAB, payload: { tabId, updates } });
  };

  return (
    <TabsContext.Provider value={{ ...state, addTab, removeTab, setActiveTab, updateTab }}>
      {children}
    </TabsContext.Provider>
  );
};

export default TabsContext;
```

