// src/components/Browser/AddressBar.tsx
import React, { useState, useEffect } from 'react';

interface AddressBarProps {
  url: string;
  onNavigate: (url: string) => void;
  onBack: () => void;
  onForward: () => void;
  onReload: () => void;
  onHome: () => void;
  isBookmarked: boolean;
  onToggleBookmark: () => void;
}

const AddressBar: React.FC<AddressBarProps> = ({
  url,
  onNavigate,
  onBack,
  onForward,
  onReload,
  onHome,
  isBookmarked,
  onToggleBookmark
}) => {
  const [inputValue, setInputValue] = useState(url);

  useEffect(() => {
    setInputValue(url);
  }, [url]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'l') {
        e.preventDefault();
        document.getElementById('url-input')?.focus();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      onNavigate(inputValue);
    }
  };

  return (
    <div className="address-bar-container">
      <div className="nav-controls">
        <button id="back-btn" title="Back" onClick={onBack}>←</button>
        <button id="forward-btn" title="Forward" onClick={onForward}>→</button>
        <button id="reload-btn" title="Reload" onClick={onReload}>↻</button>
        <button id="home-btn" title="Home" onClick={onHome}>🏠</button>
      </div>
      <input
        type="text"
        id="url-input"
        placeholder="Search Google or type a URL"
        value={inputValue}
        onChange={e => setInputValue(e.target.value)}
        onKeyDown={handleKeyDown}
        onFocus={e => e.target.select()}
      />
      <div className="address-bar-extra">
        <button
          id="add-bookmark-btn"
          title={isBookmarked ? "Remove bookmark" : "Bookmark this page"}
          onClick={onToggleBookmark}
          style={{ color: isBookmarked ? '#ffc107' : 'var(--text-secondary)' }}
        >
          ⭐
        </button>
        <button id="menu-btn" title="Menu">☰</button>
      </div>
    </div>
  );
};

export default AddressBar;
