import { useSettings } from './hooks/useSettings';
import { useBookmarks } from './hooks/useBookmarks';
import { useTabs } from './hooks/useTabs';

type WebviewRefs = {
    [key: string]: WebviewTag | null;
};

const App: React.FC = () => {
    const [isSidebarCollapsed, setSidebarCollapsed] = useState(false);
    const [currentView, setCurrentView] = useState('dashboard');
    const webviewRefs = useRef<WebviewRefs>({});

    const { settings } = useSettings();
    const { addBookmark, removeBookmark, isBookmarked } = useBookmarks();
    const { tabs, activeTabId, addTab, removeTab, setActiveTab: setActiveTabId, updateTab } = useTabs();

    const activeTab = tabs.find(t => t.id === activeTabId);

    useEffect(() => {
        if (activeTabId) {
            setCurrentView(activeTabId);
        } else if (tabs.length === 0) {
            setCurrentView('dashboard');
        }
    }, [activeTabId, tabs.length]);

    const handleNavigate = (url: string) => {
        let targetTabId = activeTabId;
        if (!targetTabId) {
            targetTabId = addTab(settings.homePage);
        }

        setTimeout(() => {
            const webview = webviewRefs.current[targetTabId!];
            if (webview) {
                let finalUrl = url.trim();
                if (!/^(https?:|file:|about:)/.test(finalUrl)) {
                    finalUrl = 'https://www.google.com/search?q=' + encodeURIComponent(finalUrl);
                }
                webview.loadURL(finalUrl);
            }
        }, 0);
    };

    const handleSidebarNavigate = (viewId: string) => {
        if (viewId === 'newTab') {
            addTab(settings.homePage);
        } else {
            setActiveTabId(null);
            setCurrentView(viewId);
        }
    };

    const handleToggleBookmark = () => {
        if (!activeTab) return;
        const { url, title } = activeTab;
        if (isBookmarked(url)) {
            removeBookmark(url);
        } else {
            addBookmark({ title, url });
        }
    };

    const webviewCommand = (command: keyof WebviewTag) => {
        const webview = activeTabId ? webviewRefs.current[activeTabId] : null;
        if (webview && typeof webview[command] === 'function') {
            (webview[command] as () => void)();
        }
    };

    const handleWebviewEvent = (tabId: string, eventName: string, e: any) => {
        switch(eventName) {
            case 'page-title-updated':
                updateTab(tabId, { title: e.title });
                break;
            case 'did-navigate':
                updateTab(tabId, { url: e.url });
                break;
        }
    };

    const NativeView = () => {
        switch(currentView) {
            case 'dashboard':
                return <Dashboard onNavigate={handleSidebarNavigate} onOpenUrlInNewTab={url => addTab(url)} />;
            case 'aiChat':
                return <AIChatHub />;
            case 'workflowBuilder':
                return <WorkflowBuilder />;
            default:
                return null;
        }
    }

    return (
        <>
            <TitleBar />
            <div className="main-container">
                <Sidebar
                    isCollapsed={isSidebarCollapsed}
                    onToggle={() => setSidebarCollapsed(!isSidebarCollapsed)}
                    activeView={!activeTabId ? currentView : null}
                    onNavigate={handleSidebarNavigate}
                />
                <main className="main-content">
                    <TabBar
                        tabs={tabs}
                        activeTabId={activeTabId}
                        onSelectTab={setActiveTabId}
                        onCloseTab={removeTab}
                        onNewTab={() => addTab(settings.homePage)}
                    />
                    <AddressBar
                        url={activeTab?.url || ''}
                        onNavigate={handleNavigate}
                        onBack={() => webviewCommand('goBack')}
                        onForward={() => webviewCommand('goForward')}
                        onReload={() => webviewCommand('reload')}
                        onHome={() => handleNavigate(settings.homePage)}
                        isBookmarked={activeTab ? isBookmarked(activeTab.url) : false}
                        onToggleBookmark={handleToggleBookmark}
                    />
                    <div id="content-area" className="content-area">
                        {tabs.map(tab => (
                            <webview
                                key={tab.id}
                                ref={(el: WebviewTag | null) => {
                                    if (el && !webviewRefs.current[tab.id]) {
                                        webviewRefs.current[tab.id] = el;
                                        el.addEventListener('page-title-updated', (e) => handleWebviewEvent(tab.id, 'page-title-updated', e));
                                        el.addEventListener('did-navigate', (e) => handleWebviewEvent(tab.id, 'did-navigate', e));
                                    }
                                }}
                                src={tab.url}
                                style={{ display: activeTabId === tab.id ? 'flex' : 'none' }}
                            ></webview>
                        ))}
                        {!activeTabId && <NativeView />}
                    </div>
                </main>
            </div>
        </>
    );
}

export default App;
